import{_ as e,c as l,o as i,ae as r}from"./chunks/framework.B7Y1jjX-.js";const p=JSON.parse('{"title":"Markdown 文档更新技能说明","description":"","frontmatter":{},"headers":[],"relativePath":"generated-notes/skill.md","filePath":"generated-notes/skill.md"}'),o={name:"generated-notes/skill.md"};function t(h,a,d,n,s,c){return i(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="markdown-文档更新技能说明" tabindex="-1">Markdown 文档更新技能说明 <a class="header-anchor" href="#markdown-文档更新技能说明" aria-label="Permalink to &quot;Markdown 文档更新技能说明&quot;">​</a></h1><p>本文档总结了处理 Markdown 文件更新任务时的通用方法，尤其适用于“扩写文档”“润色说明”“更新首页介绍”等场景。</p><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><p>当任务满足以下任意一种情况时，可以使用这套方法：</p><ul><li>需要修改已有 Markdown 文档内容。</li><li>需要在不改变主题的前提下扩写描述。</li><li>需要同时更新多个说明性文件，比如 <a href="./README.html"><code>README.md</code></a>、<a href="./"><code>index.md</code></a>、<a href="./AGENT.html"><code>AGENT.md</code></a> 等。</li><li>需要避免覆盖用户已经确认的最终版本。</li></ul><h2 id="核心原则" tabindex="-1">核心原则 <a class="header-anchor" href="#核心原则" aria-label="Permalink to &quot;核心原则&quot;">​</a></h2><h3 id="先确认基线-再修改内容" tabindex="-1">先确认基线，再修改内容 <a class="header-anchor" href="#先确认基线-再修改内容" aria-label="Permalink to &quot;先确认基线，再修改内容&quot;">​</a></h3><p>不要假设文件内容和用户提供的片段完全一致。真正修改前，应先确认当前文件的真实内容，尤其是在文件可能已被手动修改的情况下。</p><h3 id="先小改-后大改" tabindex="-1">先小改，后大改 <a class="header-anchor" href="#先小改-后大改" aria-label="Permalink to &quot;先小改，后大改&quot;">​</a></h3><p>优先使用精确替换完成局部更新。这样影响范围更小，也更容易控制变更。</p><p>如果精确替换失败，再升级为补丁更新或整体覆盖，不要一开始就使用破坏性更强的方式。</p><h3 id="最近修改的文件必须重读" tabindex="-1">最近修改的文件必须重读 <a class="header-anchor" href="#最近修改的文件必须重读" aria-label="Permalink to &quot;最近修改的文件必须重读&quot;">​</a></h3><p>如果系统提示某个文件是最近修改后的最终版本，继续编辑前必须重新读取。后续所有修改都必须基于这个新版本继续进行。</p><h2 id="标准处理步骤" tabindex="-1">标准处理步骤 <a class="header-anchor" href="#标准处理步骤" aria-label="Permalink to &quot;标准处理步骤&quot;">​</a></h2><h3 id="第一步-先读文件" tabindex="-1">第一步：先读文件 <a class="header-anchor" href="#第一步-先读文件" aria-label="Permalink to &quot;第一步：先读文件&quot;">​</a></h3><p>在准备修改 <a href="./README.html"><code>README.md</code></a> 或其他 Markdown 文件前，先读取目标文件，确认：</p><ul><li>当前内容是否和预期一致。</li><li>是否存在额外空行、格式差异或用户刚刚做过的修改。</li><li>文件是否已经是最新最终版本。</li></ul><h3 id="第二步-尝试精确替换" tabindex="-1">第二步：尝试精确替换 <a class="header-anchor" href="#第二步-尝试精确替换" aria-label="Permalink to &quot;第二步：尝试精确替换&quot;">​</a></h3><p>当只需要替换一小段文本时，优先使用精确搜索替换。这样可以：</p><ul><li>控制改动范围。</li><li>减少误修改其他内容的风险。</li><li>保持文件其余部分完全不变。</li></ul><h3 id="第三步-替换失败时先判断原因" tabindex="-1">第三步：替换失败时先判断原因 <a class="header-anchor" href="#第三步-替换失败时先判断原因" aria-label="Permalink to &quot;第三步：替换失败时先判断原因&quot;">​</a></h3><p>如果出现无法命中的情况，不要立即重复提交相同替换。应优先判断以下可能性：</p><ul><li>搜索文本与真实文本不完全一致。</li><li>存在不可见字符或换行差异。</li><li>文件内容已经在别处被修改。</li><li>上下文已经过期。</li></ul><h3 id="第四步-必要时改用补丁更新" tabindex="-1">第四步：必要时改用补丁更新 <a class="header-anchor" href="#第四步-必要时改用补丁更新" aria-label="Permalink to &quot;第四步：必要时改用补丁更新&quot;">​</a></h3><p>当文件较短，且精确替换反复失败时，改用补丁更新通常更高效。补丁方式适合：</p><ul><li>整体替换一小段文件内容。</li><li>在已知原始行内容的前提下稳定更新。</li><li>避免为不可见字符反复调试搜索文本。</li></ul><h3 id="第五步-多文件任务要拆开处理" tabindex="-1">第五步：多文件任务要拆开处理 <a class="header-anchor" href="#第五步-多文件任务要拆开处理" aria-label="Permalink to &quot;第五步：多文件任务要拆开处理&quot;">​</a></h3><p>如果同时更新多个文件，不要假设它们都能一次成功。正确做法是：</p><ul><li>确认哪些文件已经成功。</li><li>只继续处理失败的文件。</li><li>避免重复改动已经确认完成的文件。</li></ul><h2 id="常见问题与处理建议" tabindex="-1">常见问题与处理建议 <a class="header-anchor" href="#常见问题与处理建议" aria-label="Permalink to &quot;常见问题与处理建议&quot;">​</a></h2><h3 id="问题-明明看起来一样-为什么匹配失败" tabindex="-1">问题：明明看起来一样，为什么匹配失败 <a class="header-anchor" href="#问题-明明看起来一样-为什么匹配失败" aria-label="Permalink to &quot;问题：明明看起来一样，为什么匹配失败&quot;">​</a></h3><p>原因通常不是内容语义不同，而是文本字节层面不完全相同，例如换行、空格或隐藏字符不同。</p><p>建议先重新读取文件，再决定是否继续精确替换。</p><h3 id="问题-文件已经被用户改过-还能继续用旧内容改吗" tabindex="-1">问题：文件已经被用户改过，还能继续用旧内容改吗 <a class="header-anchor" href="#问题-文件已经被用户改过-还能继续用旧内容改吗" aria-label="Permalink to &quot;问题：文件已经被用户改过，还能继续用旧内容改吗&quot;">​</a></h3><p>不能。只要提示文件是最近修改后的最终版本，就必须重读。否则容易覆盖用户已确认的内容。</p><h3 id="问题-什么时候该从替换切换到补丁" tabindex="-1">问题：什么时候该从替换切换到补丁 <a class="header-anchor" href="#问题-什么时候该从替换切换到补丁" aria-label="Permalink to &quot;问题：什么时候该从替换切换到补丁&quot;">​</a></h3><p>当同一个文件多次精确替换失败，并且文件体量不大时，就应该尽快切换到补丁方式，而不是继续消耗在文本匹配上。</p><h2 id="推荐实践" tabindex="-1">推荐实践 <a class="header-anchor" href="#推荐实践" aria-label="Permalink to &quot;推荐实践&quot;">​</a></h2><ul><li>修改前先读取。</li><li>修改失败先确认基线。</li><li>多文件任务逐个确认状态。</li><li>用户已确认的文件不要重复改。</li><li>精确替换不稳定时尽快切换补丁。</li></ul><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>Markdown 文档编辑看似简单，但真正容易出错的地方往往不是写内容，而是“基于什么版本改”。只要把“先确认基线、再执行修改、失败后切换策略”这套流程固定下来，处理大多数文档更新任务都会稳定很多。</p>',41)])])}const b=e(o,[["render",t]]);export{p as __pageData,b as default};
